#!/usr/bin/env node

"use strict";

const fs = require("fs");

/**
 * Extract a field value from a GitHub issue body.
 *
 * Issue bodies generated by the template form use the pattern:
 *   ### Field Name
 *   value
 *
 * @param {string} body - The full issue body text.
 * @param {string} fieldName - The heading name to search for.
 * @returns {string} The extracted value, or empty string if not found.
 */
function extractField(body, fieldName) {
  // Match heading exactly, allowing an optional " (...)" parenthetical suffix
  // added by the auto-detection form.  This prevents "Author" from matching
  // "Author URL" or "Author Type" headings.
  const regex = new RegExp(
    `### ${fieldName}(?:\\s*\\n|\\s+\\([^\\n]*\\n)\\s*([^\\n]+)`,
    "i"
  );
  const match = body.match(regex);
  if (!match) return "";
  const value = match[1].trim();
  // Treat GitHub's default placeholder as empty
  return value === "_No response_" ? "" : value;
}

/**
 * Parse template fields from either an issue body or workflow_dispatch inputs.
 *
 * @param {object} options
 * @param {string} options.eventName - 'workflow_dispatch' or 'issues'
 * @param {string} [options.issueBody] - Issue body text (for issues event)
 * @param {object} [options.inputs] - workflow_dispatch inputs keyed by field name
 * @returns {{ fields: Record<string, string>, error?: string }}
 */
function parseIssueBody({ eventName, issueBody, inputs }) {
  const fields = {};

  if (eventName === "workflow_dispatch") {
    fields.source_repo = (inputs.source_repo || "").trim();
    fields.template_title = (inputs.template_title || "").trim();
    fields.description = (inputs.description || "").trim();
    fields.author = (inputs.author || "").trim();
    fields.author_url = (inputs.author_url || "").trim();
    fields.author_type = (inputs.author_type || "").trim();
    fields.preview_image = (inputs.preview_image || "").trim();
    fields.iac_provider = (inputs.iac_provider || "").trim();
    fields.languages = (inputs.languages || "").trim();
    fields.frameworks = (inputs.frameworks || "").trim();
    fields.azure_services = (inputs.azure_services || "").trim();
  } else {
    const body = issueBody || "";
    fields.source_repo = extractField(body, "Source Repository");
    fields.template_title = extractField(body, "Template Title");
    fields.description = extractField(body, "Description");
    fields.author = extractField(body, "Author");
    fields.author_url = extractField(body, "Author URL");
    fields.author_type = extractField(body, "Author Type");
    fields.preview_image = extractField(body, "Preview Image URL");
    fields.iac_provider = extractField(body, "IaC Provider");
    fields.languages = extractField(body, "Languages");
    fields.frameworks = extractField(body, "Frameworks");
    fields.azure_services = extractField(body, "Azure Services");
  }

  // Only the repository URL is required — the rest can be auto-extracted.
  const required = ["source_repo"];
  const missing = required.filter((k) => !fields[k]);
  if (missing.length > 0) {
    return {
      fields,
      error: `Missing required fields: ${missing.join(", ")}`,
    };
  }

  return { fields };
}

/**
 * Write key=value pairs to the GITHUB_OUTPUT file.
 * @param {string} outputPath - File path from $GITHUB_OUTPUT
 * @param {Record<string, string>} fields
 */
function writeOutputs(outputPath, fields) {
  const lines = Object.entries(fields)
    .map(([k, v]) => `${k}=${v}`)
    .join("\n");
  fs.appendFileSync(outputPath, lines + "\n");
}

// --- CLI entry point ---
if (typeof require !== "undefined" && require.main === module) {
  const outputPath = process.env.GITHUB_OUTPUT;
  if (!outputPath) {
    console.error("GITHUB_OUTPUT environment variable is not set");
    process.exit(1);
  }

  const result = parseIssueBody({
    eventName: process.env.GITHUB_EVENT_NAME,
    issueBody: process.env.ISSUE_BODY,
    inputs: {
      source_repo: process.env.INPUT_SOURCE_REPO,
      template_title: process.env.INPUT_TEMPLATE_TITLE,
      description: process.env.INPUT_DESCRIPTION,
      author: process.env.INPUT_AUTHOR,
      author_url: process.env.INPUT_AUTHOR_URL,
      author_type: process.env.INPUT_AUTHOR_TYPE,
      preview_image: process.env.INPUT_PREVIEW_IMAGE,
      iac_provider: process.env.INPUT_IAC_PROVIDER,
      languages: process.env.INPUT_LANGUAGES,
      frameworks: process.env.INPUT_FRAMEWORKS,
      azure_services: process.env.INPUT_AZURE_SERVICES,
    },
  });

  if (result.error) {
    console.error(result.error);
    process.exit(1);
  }

  writeOutputs(outputPath, result.fields);
}

module.exports = { extractField, parseIssueBody };
